using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: HasIndex now throws on Cosmos (was silently ignored in EF 8).
            // REMOVED: b.HasIndex(e => e.Name);

            // Breaking change 2: Discriminator JSON property renamed from "Discriminator" to "$type".
            // Keep the old name so existing documents are still found.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 3: The JSON "id" no longer includes the discriminator prefix.
            // Old format: "Blog|1", new format: "1".
            // Keep the old format so existing documents are still addressable.
            b.HasDiscriminatorInJsonId();
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

